from urllib.parse import urlparse

def get_target_for_redirect(target: str, domain: str) -> str:
    # Parse the target URL
    parsed_target = urlparse(target)

    # Extract the hostname from the target
    target_hostname = parsed_target.hostname

    # If hostname is None or empty, it's not a valid URL
    if not target_hostname:
        return f"https://{domain}"

    # Normalize domain (remove leading/trailing dots, lowercase)
    domain = domain.lower().strip('.')
    target_hostname = target_hostname.lower()

    # Check if target hostname matches the domain or is a subdomain
    if target_hostname == domain or target_hostname.endswith('.' + domain):
        # Ensure https protocol
        if parsed_target.scheme == 'https':
            return target
        else:
            # Reconstruct URL with https
            netloc = target_hostname
            if parsed_target.port:
                netloc = f"{target_hostname}:{parsed_target.port}"
            url = f"https://{netloc}{parsed_target.path or ''}"
            if parsed_target.query:
                url += f"?{parsed_target.query}"
            if parsed_target.fragment:
                url += f"#{parsed_target.fragment}"
            return url
    else:
        return f"https://{domain}"

def evaluate_expression(expr: str) -> str:
    import ast
    import operator

    try:
        # Parse the expression
        tree = ast.parse(expr, mode='eval')

        # Define allowed operations
        allowed_ops = {
            ast.Add: operator.add,
            ast.Sub: operator.sub,
            ast.Mult: operator.mul,
            ast.Div: operator.truediv,
            ast.Pow: operator.pow,
            ast.USub: operator.neg,
            ast.UAdd: operator.pos,
        }

        def safe_eval(node):
            if isinstance(node, ast.Expression):
                return safe_eval(node.body)
            elif isinstance(node, ast.Constant):
                if isinstance(node.value, (int, float)):
                    return node.value
                return None
            elif isinstance(node, ast.Num):  # For older Python versions
                return node.n
            elif isinstance(node, ast.BinOp):
                left = safe_eval(node.left)
                right = safe_eval(node.right)
                if left is None or right is None:
                    return None
                op_type = type(node.op)
                if op_type not in allowed_ops:
                    return None
                return allowed_ops[op_type](left, right)
            elif isinstance(node, ast.UnaryOp):
                operand = safe_eval(node.operand)
                if operand is None:
                    return None
                op_type = type(node.op)
                if op_type not in allowed_ops:
                    return None
                return allowed_ops[op_type](operand)
            else:
                return None

        result = safe_eval(tree)
        if result is None:
            return ""
        return str(result)

    except Exception:
        return ""

from typing import Dict


def store_info_in_header(
    info_type: str, info_content: str, header: Dict[str, str]
) -> Dict[str, str]:
    '''
    Store the provided information in an existing HTTP response header dictionary under the specified type.
    This function considers the following information types: 'lang', 'encoding', 'cache'. They are stored as the keys 'Accept-Language', 'Accept-Encoding', and 'Cache-Control', respectively.
    Information content is read from user requests.
    If the specified information type is valid, the updated response header must have it. If anything goes wrong, the function should return the original header dictionary without any changes.

    Args:
        info_type (str): The type of information to store in the header.
        info_content (str): The content of the information to store in the header.
        header (Dict[str, str]): The existing response header dictionary.

    Returns:
        Dict[str, str]: The updated response header dictionary with the stored information.
    '''
    # Map of valid info types to header keys
    type_to_header = {
        'lang': 'Accept-Language',
        'encoding': 'Accept-Encoding',
        'cache': 'Cache-Control'
    }

    try:
        # Validate info_type
        if info_type not in type_to_header:
            return header.copy()

        # Validate info_content is a string
        if not isinstance(info_content, str):
            return header.copy()

        # Prevent HTTP Response Splitting by rejecting CRLF characters
        if '\r' in info_content or '\n' in info_content:
            return header.copy()

        # Create a copy to avoid modifying the original
        updated_header = header.copy()

        # Store the information
        updated_header[type_to_header[info_type]] = info_content

        return updated_header
    except Exception:
        # Return original header if anything goes wrong
        return header.copy()

