class RestrictedUnpickler(pickle.Unpickler):
    ALLOWED_MODULES = {'builtins'}
    ALLOWED_BUILTINS = {'int', 'str', 'list', 'dict', 'tuple', 'set', 'bool', 'NoneType'}

    def find_class(self, module, name):
        if module not in self.ALLOWED_MODULES:
            raise pickle.UnpicklingError(f"Module '{module}' is not allowed")
        if name not in self.ALLOWED_BUILTINS:
            raise pickle.UnpicklingError(f"Built-in '{name}' is not allowed")
        return getattr(__builtins__, name)


def getPickleData(pickled):
    '''
    Return deserialized data
    '''
    if not isinstance(pickled, (bytes, str)):
        raise ValueError("Pickle data must be bytes or string")

    if isinstance(pickled, str):
        pickled = pickled.encode()

    return RestrictedUnpickler(io.BytesIO(pickled)).load()

